import KeywordCloud from './KeywordCloud.vue'
import PlotTrendChart from './PlotTrendChart.vue'
import StructureAnalysisChart from './StructureAnalysisChart.vue'

// 导出所有组件
export {
  KeywordCloud,
  PlotTrendChart,
  StructureAnalysisChart
}

// 默认导出为一个组件对象，方便批量注册
export default {
  KeywordCloud,
  PlotTrendChart,
  StructureAnalysisChart
}
